#include <stdio.h>
#include <stdlib.h>
#define MAXN 50000
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T, N, K;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int f[N * (N + 1) / 2];
        int idx = 0;
        for (int l = 0; l < N; l++) {
            for (int r = l; r < N; r++) {
                int min_val = A[l];
                int xor_val = 0;
                for (int i = l; i <= r; i++) {
                    min_val = (min_val < A[i]) ? min_val : A[i];
                    xor_val ^= A[i];
                }
                f[idx++] = min_val * xor_val;
            }
        }
        qsort(f, N * (N + 1) / 2, sizeof(int), compare);
        printf("%d\n", f[K - 1]);
    }
    return 0;
}

