import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int[] f = new int[N * (N + 1) / 2];
            int idx = 0;
            for (int l = 0; l < N; l++) {
                for (int r = l; r < N; r++) {
                    int min_val = A[l];
                    int xor_val = 0;
                    for (int i = l; i <= r; i++) {
                        min_val = Math.min(min_val, A[i]);
                        xor_val ^= A[i];
                    }
                    f[idx++] = min_val * xor_val;
                }
            }
            Arrays.sort(f);
            System.out.println(f[K - 1]);
        }
    }
}

